function solve(nums, queries) {
    const MOD = 10**9 + 7;
    const n = nums.length;
    let factors = new Array(n).fill(1);

    for (const [li, ri, ki, vi] of queries) {
        let current = li;
        while (current <= ri) {
            factors[current] = (factors[current] * vi) % MOD;
            current += ki;
        }
    }

    let xorResult = 0;
    for (let i = 0; i < n; i++) {
        const val = (nums[i] * factors[i]) % MOD;
        xorResult ^= val;
    }

    return xorResult;
}

