fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> i64 {
    const MOD: i64 = 1_000_000_007;
    let n = nums.len();
    let mut factors = vec![1; n];

    for query in queries {
        let li = query[0];
        let ri = query[1];
        let ki = query[2];
        let vi = query[3];

        let mut current = li;
        while current <= ri {
            factors[current as usize] = (factors[current as usize] * vi) % MOD;
            current += ki;
        }
    }

    let mut xor_result = 0;
    for i in 0..n {
        let val = (nums[i] * factors[i]) % MOD;
        xor_result ^= val;
    }

    xor_result
}
```

